import React, { useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import Footer from '../../components/Footer';
import '../public/Home.css';

const Home = () => {
    const navigate = useNavigate();
    const canvasRef = useRef(null);
    const deviceRef = useRef(null);

    // Particle animation with cosmic colors
    useEffect(() => {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        let animationFrameId;
        let particles = [];

        const resizeCanvas = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            initParticles();
        };

        const initParticles = () => {
            particles = [];
            const numberOfParticles = 200;
            for (let i = 0; i < numberOfParticles; i++) {
                particles.push({
                    x: Math.random() * canvas.width,
                    y: Math.random() * canvas.height,
                    radius: Math.random() * 2 + 1,
                    alpha: Math.random() * 0.6 + 0.2,
                    speedX: (Math.random() - 0.5) * 0.2,
                    speedY: (Math.random() - 0.5) * 0.2,
                    color: `hsla(${Math.random() * 60 + 200}, 70%, 60%, ${Math.random() * 0.5 + 0.3})`,
                });
            }
        };

        const drawParticles = () => {
            if (!ctx) return;
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            particles.forEach((p) => {
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
                ctx.fillStyle = p.color;
                ctx.fill();
                p.x += p.speedX;
                p.y += p.speedY;
                if (p.x < 0) p.x = canvas.width;
                if (p.x > canvas.width) p.x = 0;
                if (p.y < 0) p.y = canvas.height;
                if (p.y > canvas.height) p.y = 0;
            });
            animationFrameId = requestAnimationFrame(drawParticles);
        };

        window.addEventListener('resize', resizeCanvas);
        resizeCanvas();
        drawParticles();

        return () => {
            window.removeEventListener('resize', resizeCanvas);
            cancelAnimationFrame(animationFrameId);
        };
    }, []);

    // Mouse parallax for hero
    const handleMouseMove = (e) => {
        const hero = document.querySelector('.hero-content');
        if (!hero) return;
        const { clientX, clientY } = e;
        const x = (clientX / window.innerWidth) * 20 - 10;
        const y = (clientY / window.innerHeight) * 20 - 10;
        hero.style.transform = `perspective(1000px) rotateY(${x * 0.03}deg) rotateX(${y * -0.03}deg)`;
        if (deviceRef.current) {
            deviceRef.current.style.transform = `rotateY(${x * 0.05}deg) rotateX(${y * -0.05}deg)`;
        }
    };

    // Stats counter observer
    useEffect(() => {
        const counters = document.querySelectorAll('.stat-number');
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        const target = entry.target;
                        const updateCount = () => {
                            const targetValue = parseInt(target.getAttribute('data-target'));
                            const currentValue = parseInt(target.innerText);
                            const increment = targetValue / 200;
                            if (currentValue < targetValue) {
                                target.innerText = Math.ceil(currentValue + increment);
                                setTimeout(updateCount, 10);
                            } else {
                                target.innerText = targetValue;
                            }
                        };
                        updateCount();
                        observer.unobserve(target);
                    }
                });
            },
            { threshold: 0.5 }
        );
        counters.forEach((counter) => observer.observe(counter));
    }, []);

    return (
        <>
            <canvas ref={canvasRef} className="hero-canvas" />
            <div className="hero-section" onMouseMove={handleMouseMove}>
                <div className="container hero-container">
                    <div className="hero-content fade-in-up">
                        <div className="hero-left">
                            <div className="marvel-badge">
                                ⚡ THE ULTIMATE UNIVERSITY PLATFORM
                            </div>
                            <h1 className="marvel-title">
                                <span className="marvel-gradient">Empower</span> Your<br />
                                <span className="marvel-gradient">University Journey</span>
                            </h1>
                            <p className="marvel-subtitle">
                                UniBridge gives you superpowers: share materials, explore jobs, join study squads, and more.
                            </p>
                            <div className="marvel-btn-row">
                                <button className="btn btn-primary marvel-btn" onClick={() => navigate('/register')}>
                                    🚀 Get Started Free
                                </button>
                                <button className="btn btn-outline marvel-btn" onClick={() => navigate('/about')}>
                                    Learn More
                                </button>
                            </div>
                        </div>
                        <div className="hero-right" ref={deviceRef}>
                            <div className="device-mockup">
                                <div className="device-screen">
                                    <div className="mockup-ui">
                                        <div className="mockup-header">📚 Recent Materials</div>
                                        <div className="mockup-item">• Advanced Calculus Notes</div>
                                        <div className="mockup-item">• Data Science Roadmap</div>
                                        <div className="mockup-item">• UI/UX Case Study</div>
                                        <div className="mockup-cta">Join 5,000+ students →</div>
                                    </div>
                                </div>
                                <div className="device-shadow"></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Trusted By Section */}
            <div className="trusted-section">
                <div className="container">
                    <p className="trusted-text">Trusted by students from</p>
                    <div className="logos">
                        <span>🏛️ University of Moratuwa</span>
                        <span>🎓 University of Colombo</span>
                        <span>📚 University of Peradeniya</span>
                        <span>⚙️ SLIIT</span>
                        <span>💡 NSBM</span>
                    </div>
                </div>
            </div>

            {/* Features Section */}
            <div className="marvel-features">
                <div className="container">
                    <div className="fade-in-up delay-1">
                        <h2 className="marvel-section-title">Why Choose <span className="marvel-gradient">UniBridge?</span></h2>
                        <p className="marvel-section-desc">Everything you need to succeed – all in one heroic platform.</p>
                    </div>
                    <div className="feature-grid fade-in-up delay-2">
                        <div className="marvel-feature-card">
                            <div className="marvel-feature-icon">📚</div>
                            <h3 className="marvel-feature-title">Lecture Materials</h3>
                            <p className="marvel-feature-text">Upload & share notes, PDFs, videos. Collaborate with peers effortlessly.</p>
                        </div>
                        <div className="marvel-feature-card">
                            <div className="marvel-feature-icon">💼</div>
                            <h3 className="marvel-feature-title">Career Opportunities</h3>
                            <p className="marvel-feature-text">Find internships & jobs tailored for you. Apply with one click.</p>
                        </div>
                        <div className="marvel-feature-card">
                            <div className="marvel-feature-icon">🎓</div>
                            <h3 className="marvel-feature-title">Peer Study Hub</h3>
                            <p className="marvel-feature-text">Create or join 'Kuppi' sessions. Prepare for exams together.</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* How It Works Section */}
            <div className="how-it-works">
                <div className="container">
                    <h2 className="marvel-section-title">How <span className="marvel-gradient">It Works</span></h2>
                    <p className="marvel-section-desc">Three simple steps to unlock your potential</p>
                    <div className="steps-grid">
                        <div className="step-card">
                            <div className="step-number">1</div>
                            <h3>Sign Up Free</h3>
                            <p>Create your account in seconds – no credit card required.</p>
                        </div>
                        <div className="step-card">
                            <div className="step-number">2</div>
                            <h3>Explore Resources</h3>
                            <p>Access thousands of materials, jobs, and study groups.</p>
                        </div>
                        <div className="step-card">
                            <div className="step-number">3</div>
                            <h3>Collaborate & Grow</h3>
                            <p>Connect with peers, share knowledge, and advance your career.</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Statistics Section */}
            <div className="stats-section fade-in-up delay-3">
                <div className="stat-item">
                    <div className="stat-number" data-target="5000">0</div>
                    <div className="stat-label">Active Students</div>
                </div>
                <div className="stat-item">
                    <div className="stat-number" data-target="1200">0</div>
                    <div className="stat-label">Materials Shared</div>
                </div>
                <div className="stat-item">
                    <div className="stat-number" data-target="350">0</div>
                    <div className="stat-label">Job Listings</div>
                </div>
                <div className="stat-item">
                    <div className="stat-number" data-target="150">0</div>
                    <div className="stat-label">Study Groups</div>
                </div>
            </div>

            {/* Testimonials Section */}
            <div className="testimonials">
                <div className="container">
                    <h2 className="marvel-section-title">What <span className="marvel-gradient">Students Say</span></h2>
                    <div className="testimonial-grid">
                        <div className="testimonial-card">
                            <p>"UniBridge completely changed how I study. The materials and community are incredible!"</p>
                            <h4>— Sarah J., Computer Science</h4>
                        </div>
                        <div className="testimonial-card">
                            <p>"Found my dream internship through the job board. Highly recommended!"</p>
                            <h4>— Michael T., Business</h4>
                        </div>
                        <div className="testimonial-card">
                            <p>"The study squads helped me ace my finals. Best platform for students."</p>
                            <h4>— Priya K., Engineering</h4>
                        </div>
                    </div>
                </div>
            </div>

            {/* Blog / Latest News Section */}
            <div className="blog-section">
                <div className="container">
                    <h2 className="marvel-section-title">Latest <span className="marvel-gradient">News & Updates</span></h2>
                    <div className="blog-grid">
                        <div className="blog-card">
                            <div className="blog-date">March 15, 2026</div>
                            <h3>New Partnership with Tech Giants</h3>
                            <p>UniBridge collaborates with leading tech companies to bring exclusive internships.</p>
                            <a href="#" className="read-more">Read more →</a>
                        </div>
                        <div className="blog-card">
                            <div className="blog-date">March 10, 2026</div>
                            <h3>Introducing AI Study Assistant</h3>
                            <p>Get personalized study plans and material recommendations.</p>
                            <a href="#" className="read-more">Read more →</a>
                        </div>
                        <div className="blog-card">
                            <div className="blog-date">March 5, 2026</div>
                            <h3>5,000+ Students Joined!</h3>
                            <p>We've hit a major milestone – thank you to our amazing community.</p>
                            <a href="#" className="read-more">Read more →</a>
                        </div>
                    </div>
                </div>
            </div>

            {/* CTA Section */}
            <div className="marvel-cta fade-in-up delay-3">
                <div className="container">
                    <h2 className="marvel-cta-title">Ready to bridge the gap?</h2>
                    <p className="marvel-cta-desc">Join completely free and start exploring resources and opportunities today.</p>
                    <button className="btn marvel-btn" onClick={() => navigate('/register')}>
                        Create an Account
                    </button>
                </div>
            </div>

            <Footer />
        </>
    );
};

export default Home;
